const raw = $('Medi - AI Receptionist').first().json.output ?? '';

const MARKER = '[INQUIRER_DATA]';
const idx = raw.indexOf(MARKER);

// reply = everything BEFORE the marker (this is the only fix that matters)
let reply = idx === -1 ? raw : raw.slice(0, idx);
reply = reply.trim();

// data = the JSON block AFTER the marker
let data = {};
if (idx !== -1) {
  try {
    data = JSON.parse(raw.slice(idx + MARKER.length).trim());
  } catch (e) {
    data = {}; // malformed block — don't crash, just log nothing
  }
}

const hasData = Boolean(
  data.name || data.contact || data.appointment_date || data.service_interested
);

return [{
  json: {
    reply,
    sessionId: $('ReceiveChatMessage').first().json.body.sessionId ?? 'anonymous',
    timestamp: new Date().toISOString(),
    name: data.name ?? null,
    contact: data.contact ?? null,
    intent: data.intent ?? null,
    service_interested: data.service_interested ?? null,
    appointment_date: data.appointment_date ?? null,
    appointment_time: data.appointment_time ?? null,
    doctor_preference: data.doctor_preference ?? null,
    reason_for_visit: data.reason_for_visit ?? null,
    conversation_summary: data.conversation_summary ?? null,
    status: data.status ?? 'new',
    hasData,
  },
}];
